const Icon=({name,size=21})=><svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">{iconPaths[name]}</svg>;
const Container=({children,className=''})=><div className={`container ${className}`}>{children}</div>;
const Brand=({light=false})=><a href="#home" className={`brand ${light?'brand-light':''}`} aria-label="EDOX Logistics home"><span className="brand-star" aria-hidden="true">✦</span><span className="brand-word"><strong>EDOX</strong><small>LOGISTICS</small></span></a>;
const Button=({href,children,secondary=false})=><a className={`button ${secondary?'button-secondary':'button-primary'}`} href={href}>{children}<Icon name="arrow" size={17}/></a>;

function Topbar({t,lang,setLang}){return <div className="topbar"><Container className="topbar-inner"><div className="top-contact"><a href={`tel:${SITE.phone}`}><Icon name="phone" size={14}/>{SITE.phoneDisplay}</a><a href={`mailto:${SITE.email}`}><Icon name="mail" size={14}/>{SITE.email}</a></div><span className="top-message">{t.topbar}</span><div className="top-actions"><a href={SITE.instagram} target="_blank" rel="noreferrer" aria-label="Instagram"><Icon name="instagram" size={15}/></a><a href={SITE.linkedin} target="_blank" rel="noreferrer" aria-label="LinkedIn"><Icon name="linkedin" size={15}/></a><div className="language-switch" aria-label="Language selector">{['nl','en','ru'].map(x=><button key={x} className={lang===x?'active':''} onClick={()=>setLang(x)} lang={x}>{x.toUpperCase()}</button>)}</div></div></Container></div>}
function Header({t}){const[open,setOpen]=useState(false);const ids=['home','opdrachtgevers','chauffeurs','diensten','werkwijze','offerte','contact'];return <header className="header"><Container className="header-inner"><Brand/><nav id="main-nav" className={open?'nav open':'nav'} aria-label="Main navigation">{t.nav.map((x,i)=><a key={x} href={`#${ids[i]}`} onClick={()=>setOpen(false)}>{x}</a>)}<div className="mobile-nav-ctas"><Button href="#offerte">{t.quote}</Button><Button href="#chauffeurs" secondary>{t.driverCta}</Button></div></nav><div className="header-ctas"><Button href="#offerte">{t.quote}</Button><Button href="#chauffeurs" secondary>{t.driverCta}</Button></div><button className="menu-button" onClick={()=>setOpen(!open)} aria-expanded={open} aria-controls="main-nav" aria-label={open?'Close menu':'Open menu'}><Icon name={open?'close':'menu'}/></button></Container></header>}
function SectionHead({kicker,title,text,light=false,center=false}){return <div className={`section-head ${light?'light':''} ${center?'center':''}`}><span className="kicker">{kicker}</span><h2>{title}</h2>{text&&<p>{text}</p>}</div>}

function Hero({t}){return <section className="hero" id="home" style={{'--hero-image':`url(${SITE.heroImage})`}}><div className="hero-overlay"/><div className="hero-lines"/><Container className="hero-content"><div className="hero-copy"><div className="hero-brandline"><span>EDOX LOGISTICS</span><i/></div><h1>{t.heroTitle}</h1><strong className="slogan">FAST <b>•</b> STRONG <b>•</b> TRUSTED</strong><p>{t.heroText}</p><div className="hero-buttons"><Button href="#offerte">{t.quote}</Button><Button href="#chauffeurs" secondary>{t.heroDriver}</Button></div><div className="hero-badges">{t.trustBadges.map((x,i)=><span key={x}><Icon name={['check','driver','route','globe'][i]} size={16}/>{x}</span>)}</div></div></Container><div className="hero-route-label"><span>NL</span><i/><span>DE</span><i/><span>BE</span><i/><span>EU</span></div></section>}

function Clients({t}){return <section className="section clients" id="opdrachtgevers"><Container className="split"><div><SectionHead kicker={t.clientKicker} title={t.clientTitle} text={t.clientText}/><div className="check-grid">{t.clientBullets.map(x=><span key={x}><Icon name="check" size={15}/>{x}</span>)}</div><Button href="#offerte">{t.clientCta}</Button></div><div className="image-panel client-image" role="img" aria-label="EDOX Logistics transport network in Western Europe"><span className="image-label">WESTERN EUROPE</span><div className="route-map"><b>NL</b><i/><b>DE</b><i/><b>BE</b></div><div className="image-stat"><strong>3</strong><span>core<br/>markets</span></div></div></Container></section>}

function DriverForm({t}){const[done,setDone]=useState(false);const submit=e=>{e.preventDefault();setDone(true);e.currentTarget.reset();};return <form className="compact-form" onSubmit={submit}>{done&&<div className="success" role="status"><Icon name="check"/>{t.driverSuccess}</div>}<div className="form-row three"><Field label={`${t.labels.name} *`} name="driverName" required/><Field type="email" label={`${t.labels.email} *`} name="driverEmail" required/><Field type="tel" label={`${t.labels.phone} *`} name="driverPhone" required/></div><div className="form-row three"><Select label={`${t.labels.language} (${t.labels.optional})`} name="language" options={['Nederlands','English','Русский']}/><Field label={`${t.labels.country} (${t.labels.optional})`} name="country"/><Select label={`${t.labels.license} (${t.labels.optional})`} name="license" options={['CE','C','Anders / Other']}/></div><Field textarea label={`${t.labels.message} (${t.labels.optional})`} name="driverMessage"/><button type="submit" className="button button-primary full">{t.submitDriver}<Icon name="arrow" size={17}/></button>{/* KOPPELPUNT CHAUFFEUR: vervang submit-handler door Netlify Forms, Formspree, EmailJS of API. */}</form>}
function Drivers({t}){return <section className="section drivers" id="chauffeurs"><Container><div className="driver-shell"><div className="driver-copy"><SectionHead light kicker={t.driverKicker} title={t.driverTitle} text={t.driverText}/><p className="driver-regions"><Icon name="globe" size={17}/>{t.driverRegions}</p><div className="driver-photo-slot" role="img" aria-label="International CE driver at an EDOX Logistics truck"><span>// EDOX DRIVER NETWORK</span></div><p className="reassure"><Icon name="check" size={16}/>{t.driverReassure}</p></div><DriverForm t={t}/></div></Container></section>}

function Trust({t}){const icons=['clock','driver','message','globe'];return <section className="section trust"><Container><SectionHead center kicker={t.trustKicker} title={t.trustTitle}/><div className="trust-grid">{t.trust.map((x,i)=><article key={x[0]} className="trust-card"><span className="number">0{i+1}</span><div className="icon"><Icon name={icons[i]}/></div><h3>{x[0]}</h3><p>{x[1]}</p></article>)}</div></Container></section>}
function Services({t}){const icons=['truck','globe','driver','route','building','box'];return <section className="section services" id="diensten"><Container><SectionHead center kicker={t.servicesKicker} title={t.servicesTitle} text={t.servicesIntro}/><div className="services-grid">{t.services.map((x,i)=><article className="service-card" key={x[0]}><div className="service-icon"><Icon name={icons[i]} size={24}/></div><small>0{i+1}</small><h3>{x[0]}</h3><p>{x[1]}</p><a href="#offerte">{t.quote}<Icon name="arrow" size={16}/></a></article>)}</div></Container></section>}
function Problem({t}){return <section className="section problem"><Container><SectionHead kicker={t.problemKicker} title={t.problemTitle}/><div className="problem-grid"><article className="problem-card problem-dark"><span>{t.problemLabel}</span><h3>{t.problemHead}</h3><p>{t.problemText}</p><div className="delay-bars"><i/><i/><i/><i/></div></article><article className="problem-card solution"><span>{t.solutionLabel}</span><h3>{t.solutionHead}</h3><p>{t.solutionText}</p><ul>{t.solutionBullets.map(x=><li key={x}><Icon name="check" size={15}/>{x}</li>)}</ul></article><div className="problem-photo" role="img" aria-label="EDOX Logistics truck and route planning"><span>EDOX / ON THE ROAD</span></div></div></Container></section>}
function Process({t}){return <section className="section process" id="werkwijze"><Container><SectionHead light kicker={t.processKicker} title={t.processTitle}/><div className="steps">{t.steps.map((x,i)=><article key={x[0]}><div className="step-no">0{i+1}</div><i/><h3>{x[0]}</h3><p>{x[1]}</p></article>)}</div></Container></section>}

function Field({label,name,type='text',required=false,textarea=false}){return <label>{label}{textarea?<textarea name={name} rows="3"/>:<input name={name} type={type} required={required}/>}</label>}
function Select({label,name,options,required=false}){return <label>{label}<select name={name} required={required}><option value="">—</option>{options.map(x=><option value={x} key={x}>{x}</option>)}</select></label>}
function AddressFields({t,prefix,dateLabel}){return <><div className="form-row">{dateLabel&&<Field type="date" label={dateLabel} name={`${prefix}Date`}/>}<Field label={t.labels.country} name={`${prefix}Country`}/></div><Field label={t.labels.street} name={`${prefix}Street`}/><div className="form-row"><Field label={t.labels.postcode} name={`${prefix}Postcode`}/><Field label={t.labels.city} name={`${prefix}City`}/></div></>}
function QuoteForm({t}){const[done,setDone]=useState(false);const submit=e=>{e.preventDefault();setDone(true);e.currentTarget.reset();};return <form className="quote-form" onSubmit={submit}>{done&&<div className="success" role="status"><Icon name="check"/>{t.quoteSuccess}</div>}<fieldset><legend><span>01</span>{t.groups[0]}</legend><div className="form-row"><Field label={`${t.labels.company} *`} name="company" required/><Field label={`${t.labels.contact} *`} name="contact" required/></div><div className="form-row"><Field type="email" label={`${t.labels.email} *`} name="email" required/><Field type="tel" label={`${t.labels.phone} *`} name="phone" required/></div></fieldset><fieldset><legend><span>02</span>{t.groups[1]}</legend><AddressFields t={t} prefix="client"/></fieldset><fieldset><legend><span>03</span>{t.groups[2]}</legend><div className="form-row three"><Field label={`${t.labels.goods} *`} name="goods" required/><Field type="number" label={t.labels.weight} name="weight"/><Field type="number" label={t.labels.volume} name="volume"/></div><Select label={`${t.labels.service} *`} name="service" options={serviceValues} required/><Field textarea label={t.labels.notes} name="notes"/></fieldset><div className="address-pair"><fieldset><legend><span>04</span>{t.groups[3]}</legend><AddressFields t={t} prefix="load" dateLabel={t.labels.dateLoad}/></fieldset><fieldset><legend><span>05</span>{t.groups[4]}</legend><AddressFields t={t} prefix="unload" dateLabel={t.labels.dateUnload}/></fieldset></div><label className="privacy-check"><input type="checkbox" required/><span>{t.labels.privacy}</span></label><button type="submit" className="button button-primary quote-submit">{t.submitQuote}<Icon name="arrow" size={18}/></button>{/* KOPPELPUNT OFFERTE: voeg action/endpoint toe voor Netlify, Formspree, EmailJS of backend API. */}</form>}
function Quote({t}){return <section className="section quote" id="offerte"><Container><SectionHead kicker={t.quoteKicker} title={t.quoteTitle} text={t.quoteIntro}/><QuoteForm t={t}/></Container></section>}

function Social({t}){return <section className="section social"><Container><SectionHead center kicker={t.socialKicker} title={t.socialTitle} text={t.socialText}/><div className="social-grid">{t.socialCards.map((x,i)=><article key={x[0]} className={`social-card social-${i+1}`}><span>{['01 / BRAND','02 / DRIVERS','03 / CAPACITY'][i]}</span><div className="social-symbol">{['✦','CE','→'][i]}</div><h3>{x[0]}</h3><p>{x[1]}</p><a href={i===1?'#chauffeurs':'#offerte'}>{i===1?t.driverCta:t.quote}<Icon name="arrow" size={15}/></a></article>)}</div><div className="social-links"><a href={SITE.instagram} target="_blank" rel="noreferrer"><Icon name="instagram"/>Instagram</a><a href={SITE.linkedin} target="_blank" rel="noreferrer"><Icon name="linkedin"/>LinkedIn</a></div></Container></section>}
function About({t}){return <section className="section about"><Container className="about-grid"><div className="about-photo" role="img" aria-label="EDOX Logistics team, driver and truck placeholder"><span>// TEAM / OWNER / TRUCK</span><div className="about-mark">E</div></div><div><SectionHead kicker={t.aboutKicker} title={t.aboutTitle} text={t.aboutText}/><strong className="slogan dark">FAST <b>•</b> STRONG <b>•</b> TRUSTED</strong><div className="values">{['FAST','STRONG','TRUSTED'].map((x,i)=><span key={x}><small>0{i+1}</small>{x}</span>)}</div></div></Container></section>}
function Seo({t}){return <section className="seo"><Container><div className="seo-content"><span><Icon name="route"/></span><div><h2>{t.seoTitle}</h2><p>{t.seoText}</p></div></div></Container></section>}
function CTA({t}){return <section className="cta"><div className="cta-lines"/><Container><div><span className="kicker">EDOX LOGISTICS</span><h2>{t.ctaTitle}</h2><p>{t.ctaText}</p></div><div><Button href="#offerte">{t.quote}</Button><Button href="#chauffeurs" secondary>{t.driverCta}</Button></div></Container></section>}
function Contact({t}){return <section className="section contact" id="contact"><Container><SectionHead center kicker={t.contactKicker} title={t.contactTitle}/><div className="contact-grid"><a href={`tel:${SITE.phone}`}><span><Icon name="phone"/></span><small>{t.labels.phone}</small><strong>{SITE.phoneDisplay}</strong></a><a href={`mailto:${SITE.email}`}><span><Icon name="mail"/></span><small>{t.labels.email}</small><strong>{SITE.email}</strong></a><div><span><Icon name="globe"/></span><small>WORK AREA</small><strong>{t.workArea}</strong></div></div><div className="contact-paths"><a href="#chauffeurs"><b>{t.forDrivers}</b><span>{t.forDriversText}</span><Icon name="arrow"/></a><a href="#offerte"><b>{t.forClients}</b><span>{t.forClientsText}</span><Icon name="arrow"/></a></div></Container></section>}
function Footer({t}){return <footer><Container><div className="footer-grid"><div><Brand light/><p>{t.footerText}</p><strong className="slogan">FAST • STRONG • TRUSTED</strong></div><div><h3>{t.contactKicker}</h3><a href={`tel:${SITE.phone}`}>{SITE.phoneDisplay}</a><a href={`mailto:${SITE.email}`}>{SITE.email}</a><span>{t.workArea}</span></div><div><h3>{t.companyData}</h3><span>KvK: 00000000</span><span>BTW: NL000000000B00</span><span>Vestigingsplaats, Nederland</span></div><div><h3>Social</h3><a href={SITE.instagram} target="_blank" rel="noreferrer">Instagram</a><a href={SITE.linkedin} target="_blank" rel="noreferrer">LinkedIn</a><a href="#contact">{t.nav[6]}</a></div></div><div className="footer-bottom"><span>© {new Date().getFullYear()} EDOX Logistics. {t.rights}</span><div><a href="#">{t.privacy}</a><a href="#">{t.terms}</a></div></div></Container></footer>}

function StructuredData(){useEffect(()=>{const script=document.createElement('script');script.type='application/ld+json';script.id='edox-structured-data';script.text=JSON.stringify({'@context':'https://schema.org','@type':['Organization','LocalBusiness'],'additionalType':'https://schema.org/TransportBusiness',name:SITE.name,url:'https://arixconnect.github.io/logistiek/',email:SITE.email,telephone:SITE.phone,address:{'@type':'PostalAddress',addressCountry:'NL'},areaServed:['Netherlands','Germany','Belgium','Western Europe'],sameAs:[SITE.instagram,SITE.linkedin],contactPoint:{'@type':'ContactPoint',telephone:SITE.phone,email:SITE.email,contactType:'sales',availableLanguage:['Dutch','English','Russian']}});document.head.appendChild(script);return()=>script.remove();},[]);return null}
function App(){const initial=(()=>{const query=new URLSearchParams(location.search).get('lang');return ['nl','en','ru'].includes(query)?query:'nl';})();const[lang,setLangState]=useState(initial);const t=translations[lang];const setLang=x=>{setLangState(x);const url=new URL(location.href);x==='nl'?url.searchParams.delete('lang'):url.searchParams.set('lang',x);history.replaceState({},'',url);};useEffect(()=>{document.documentElement.lang=t.locale;document.title=lang==='nl'?'EDOX Logistics | Transportbedrijf Nederland & CE-bestuurders':lang==='en'?'EDOX Logistics | Transport company & CE drivers':'EDOX Logistics | Транспорт и водители CE';document.querySelector('meta[name="description"]')?.setAttribute('content',lang==='nl'?'EDOX Logistics is een transportbedrijf voor Nederland, Duitsland en België. Betrouwbare CE-bestuurders, chauffeursdiensten en transportcapaciteit. FAST • STRONG • TRUSTED.':t.heroText);},[lang,t]);return <><StructuredData/><Topbar t={t} lang={lang} setLang={setLang}/><Header t={t}/><main><Hero t={t}/><Clients t={t}/><Drivers t={t}/><Trust t={t}/><Services t={t}/><Problem t={t}/><Process t={t}/><Quote t={t}/><Social t={t}/><About t={t}/><Seo t={t}/><CTA t={t}/><Contact t={t}/></main><Footer t={t}/></>}

createRoot(document.getElementById('root')).render(<React.StrictMode><App/></React.StrictMode>);
